INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "", "omp_talk_joy1", 0, 3, 1, "", 1030019, 112611, 3, "");
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES (0, "", "vo_omp_7003_003", "", 3, 0, "", 1030020, "vo_omp_7003", 21, "");
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES (1, 1, "そういうことか\nいや、ちょっとまって、しまむー\nプチグリフォンはかわいいかもだけど\nぴにゃこら太、かわいいかな～？", "", 3, 10, "", 1030021, 112611, 11, "");
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "", 1, "", 3, "", "", 1030022, 1.5, 93, "");
