INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES (0, "", "vo_omp_7003_004", "", 3, 0, "", 1030027, "vo_omp_7003", 21, "");
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES (1, 1, "かわいいですよ～\n私たちの歌で、たくさんの\nぴにゃこら太さんを\n集められませんかね？", "", 3, 10, "", 1030028, 112411, 11, "");
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "", "", "", 3, "", "", 1030029, 0, 91, "");
