INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES (1, 1, "でも、自分たちで立ち上がって\n再び舞台に立つ姿…\nわたくし、感動いたしました", "", 7, 10, "", 1070041, 105931, 11, "");
